#include<bits/stdc++.h>
using namespace std;
struct Time{
    int y,mo,d,h,mi;
}s,t;
int n,a[5003],sum[5003];
bool b[13];
int main(){
    scanf("%d",&n);
    for(int i=1;i<=n;i++)
        scanf("%d",&a[i]);
    sort(a+1,a+n+1);
    for(int i=1;i<=n;i++)
        sum[i]=a[i]+sum[i-1];
    scanf("%d-%d-%d-%d:%d",&s.y,&s.mo,&s.d,&s.h,&s.mi);
    scanf("%d-%d-%d-%d:%d",&t.y,&t.mo,&t.d,&t.h,&t.mi);
    b[1]=b[3]=b[5]=b[7]=b[8]=b[10]=b[12]=1;
    int sums=0,sumt=0;
    for(int i=0;i<t.y;i++)
        sumt+=365+(i%4==0 && i%100 || i%400==0);
    sumt*=24*60;
    for(int i=1;i<t.mo;i++)
        if(i==2)
            sumt+=(28+(t.y%4==0 && t.y%100 || t.y%400==0))*24*60;
        else
            sumt+=(30+b[i])*24*60;
    sumt+=t.d*24*60+t.h*60+t.mi;
    for(int i=0;i<s.y;i++)
        sums+=365+(i%4==0 && i%100 || i%400==0);
    sums*=24*60;
    for(int i=1;i<s.mo;i++)
        if(i==2)
            sums+=(28+(s.y%4==0 && s.y%100 || s.y%400==0))*24*60;
        else
            sums+=(30+b[i])*24*60;
    sums+=s.d*24*60+s.h*60+s.mi;
    int ans=sumt-sums;
    for(int i=1;i<=n;i++)
        if(sum[i]>ans){
            cout<<i-1;
            return 0;
        }
    cout<<n<<endl;
    return 0;
}
